import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../../context/AuthContext';
import AdminNavbar from './AdminNavbar';
import AdminSidebar from './AdminSidebar';
import CertificatesList from './CertificatesList';
import UsersList from './UsersList';
import Statistics from './Statistics';

const AdminDashboard = () => {
  const [currentView, setCurrentView] = useState('overview');
  const [certificates, setCertificates] = useState([]);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [stats, setStats] = useState({
    totalCertificates: 0,
    totalUsers: 0,
    recentCertificates: 0,
    revenue: 0
  });
  
  const { currentUser, logout } = useContext(AuthContext);
  
  useEffect(() => {
    const fetchDashboardData = async () => {
      setLoading(true);
      setError(null);
      
      try {
        const token = localStorage.getItem('token');
        
        if (!token) {
          throw new Error('Not authenticated');
        }
        
        // Fetch statistics
        const statsResponse = await fetch('/api/admin/statistics', {
          headers: {
            'Authorization': `Bearer ${token}`
          }
        });
        
        if (!statsResponse.ok) {
          throw new Error('Failed to fetch statistics');
        }
        
        const statsData = await statsResponse.json();
        setStats(statsData.data);
        
        // Fetch certificates if on the certificates view
        if (currentView === 'certificates') {
          const certsResponse = await fetch('/api/admin/certificates', {
            headers: {
              'Authorization': `Bearer ${token}`
            }
          });
          
          if (!certsResponse.ok) {
            throw new Error('Failed to fetch certificates');
          }
          
          const certsData = await certsResponse.json();
          setCertificates(certsData.data);
        }
        
        // Fetch users if on the users view
        if (currentView === 'users') {
          const usersResponse = await fetch('/api/admin/users', {
            headers: {
              'Authorization': `Bearer ${token}`
            }
          });
          
          if (!usersResponse.ok) {
            throw new Error('Failed to fetch users');
          }
          
          const usersData = await usersResponse.json();
          setUsers(usersData.data);
        }
      } catch (err) {
        console.error('Dashboard data fetch error:', err);
        setError(err.message);
        
        if (err.message === 'Not authenticated') {
          logout();
        }
      } finally {
        setLoading(false);
      }
    };
    
    fetchDashboardData();
  }, [currentView, logout]);
  
  // Mock data for development
  useEffect(() => {
    if (process.env.NODE_ENV === 'development') {
      setStats({
        totalCertificates: 156,
        totalUsers: 89,
        recentCertificates: 24,
        revenue: 7850
      });
      
      setCertificates([
        { 
          _id: '1', 
          certificateId: 'GHU-2023-1234', 
          name: 'John Doe', 
          program: 'MBA', 
          date: '2023-06-15',
          status: 'issued'
        },
        { 
          _id: '2', 
          certificateId: 'GHU-2023-5678', 
          name: 'Jane Smith', 
          program: 'BSc', 
          date: '2023-07-22',
          status: 'issued'
        },
        { 
          _id: '3', 
          certificateId: 'GHU-2023-9012', 
          name: 'Michael Brown', 
          program: 'Certificate', 
          date: '2023-08-10',
          status: 'pending'
        }
      ]);
      
      setUsers([
        {
          _id: '1',
          name: 'Admin User',
          email: 'admin@example.com',
          role: 'admin',
          createdAt: '2023-01-15'
        },
        {
          _id: '2',
          name: 'John Doe',
          email: 'john@example.com',
          role: 'user',
          createdAt: '2023-05-20'
        },
        {
          _id: '3',
          name: 'Jane Smith',
          email: 'jane@example.com',
          role: 'user',
          createdAt: '2023-06-10'
        }
      ]);
      
      setLoading(false);
    }
  }, [currentView]);
  
  const handleViewChange = (view) => {
    setCurrentView(view);
  };
  
  const renderContent = () => {
    switch (currentView) {
      case 'overview':
        return <Statistics stats={stats} />;
      case 'certificates':
        return <CertificatesList certificates={certificates} />;
      case 'users':
        return <UsersList users={users} />;
      default:
        return <Statistics stats={stats} />;
    }
  };
  
  if (loading) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center">
        <div className="text-xl font-semibold text-blue-900">Loading...</div>
      </div>
    );
  }
  
  return (
    <div className="bg-gray-100 min-h-screen">
      <div className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
        <h1 className="text-2xl font-bold text-gray-900 mb-6">
          {currentView === 'overview' && 'Dashboard Overview'}
          {currentView === 'certificates' && 'Certificates Management'}
          {currentView === 'users' && 'Users Management'}
        </h1>
        
        {error && (
          <div className="mb-6 p-4 bg-red-50 text-red-700 border border-red-200 rounded-md">
            {error}
          </div>
        )}
        
        {renderContent()}
      </div>
    </div>
  );
};

export default AdminDashboard;
